INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Leadership & RH : Management d''équipe, résolution des conflits & motivation', 'Formation sur l’utilisation de l’IA pour optimiser la prospection, la vente et la relation client.', 5, 200000.00, 'entreprise', '2026-12-05', 30, '2026-01-14 12:38:42', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre le rôle de l’IA dans la vente\n• Utiliser des outils IA pour automatiser et analyser les processus commerciaux\n• Développer des stratégies basées sur les données et insights IA\n• Améliorer la prospection, le scoring et la conversion client\n• Piloter la performance commerciale grâce aux outils IA\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre l’impact de l’IA sur la vente et le management commercial, utiliser des outils IA pour automatiser et optimiser les processus, développer des stratégies commerciales basées sur les données, améliorer la prospection et la conversion client et mesurer la performance commerciale.\n\n--- PRÉREQUIS ---\nConnaissances de base en vente ou marketing. Familiarité avec les outils numériques recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction à l’IA et son impact sur la vente\nModule 2 : Outils d’IA pour la performance commerciale\nModule 3 : Stratégies gagnantes basées sur l’IA\nModule 4 : Optimisation de la relation client\nModule 5 : Pilotage et mesure de la performance commerciale\nModule 6 : Mise en œuvre et bonnes pratiques\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nCommerciaux, chargés d’affaires, managers, responsables d’équipes commerciales, responsables marketing et CRM, consultants en stratégie commerciale.\n\n--- MÉTHODES ---\nApports théoriques interactifs, études de cas, ateliers pratiques, mises en situation sur outils IA, jeux de rôle et simulations commerciales.\n\n--- SUPPORTS ---\nCRM intelligents, chatbots, outils de scoring, dashboards IA, guides pratiques, modèles de suivi client, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
